/*
 * atan2f() test harness — prints (y_hex, x_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float y, float x)
{
    float r = atan2f(y, x);
    printf("%08lx %08lx %08lx\n", (unsigned long)f2u(y), (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t y_bits, uint32_t x_bits)
{
    emit(u2f(y_bits), u2f(x_bits));
}

/* Test special values */
static void test_special(void)
{
    /* Zero cases */
    emit(0.0f, 1.0f);
    emit(-0.0f, 1.0f);
    emit(1.0f, 0.0f);
    emit(1.0f, -0.0f);
    emit(0.0f, 0.0f);
    emit(-0.0f, -0.0f);

    /* With infinity */
    emit_u(0x7f800000u, 0x7f800000u);  /* +Inf, +Inf */
    emit_u(0x7f800000u, 0xff800000u);  /* +Inf, -Inf */
    emit_u(0xff800000u, 0x7f800000u);  /* -Inf, +Inf */
    emit_u(0xff800000u, 0xff800000u);  /* -Inf, -Inf */
    emit(1.0f, INFINITY);
    emit(1.0f, -INFINITY);
    emit(INFINITY, 1.0f);
    emit(-INFINITY, 1.0f);

    /* With NaN */
    emit_u(0x7fc00000u, 0x3f800000u);  /* qNaN, 1.0 */
    emit_u(0x3f800000u, 0x7fc00000u);  /* 1.0, qNaN */
    emit_u(0x7fc00000u, 0x7fc00000u);  /* qNaN, qNaN */
}

/* Test quadrants */
static void test_quadrants(void)
{
    emit(1.0f, 1.0f);    /* Q1 */
    emit(1.0f, -1.0f);   /* Q2 */
    emit(-1.0f, -1.0f);  /* Q3 */
    emit(-1.0f, 1.0f);   /* Q4 */
}

/* Test small values */
static void test_small(void)
{
    emit_u(0x00000001u, 0x3f800000u);
    emit_u(0x3f800000u, 0x00000001u);
    emit(1.0e-20f, 1.0f);
    emit(1.0f, 1.0e-20f);
    emit(1.0e-10f, 1.0e-10f);
}

/* Test various ratios */
static void test_ratios(void)
{
    float vals[] = { 0.1f, 0.5f, 1.0f, 2.0f, 10.0f };
    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < 5; j++) {
            emit(vals[i], vals[j]);
            emit(-vals[i], vals[j]);
            emit(vals[i], -vals[j]);
        }
    }
}

/* Test large magnitudes */
static void test_large(void)
{
    emit(1e10f, 1e10f);
    emit(1e20f, 1e20f);
    emit(FLT_MAX, FLT_MAX);
    emit(-FLT_MAX, FLT_MAX);
}

int main(void)
{
    test_special();
    test_quadrants();
    test_small();
    test_ratios();
    test_large();
    return 0;
}

