        emit(vals[i]);

    /* sweep [-4*pi, 4*pi] */
    float hi = 4.0f * 3.14159265f;
    for (int i = 0; i <= 200; i++)
        emit(-hi + (2.0f * hi) * (float)i / 200.0f);

    return 0;
}

