#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float r = expf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

int main(void)
{
    /* specials */
    emit(0.0f); emit(-0.0f);
    emit(u2f(0x7fc00000u)); emit(u2f(0x7f800000u)); emit(u2f(0xff800000u));
    emit(u2f(0x00000001u)); emit(u2f(0x80000001u)); emit(u2f(0x007fffffu));

    /* normal range */
    float vals[] = {
        0.1f, -0.1f, 0.5f, -0.5f, 1.0f, -1.0f,
        1.5f, -1.5f, 2.0f, -2.0f, 3.0f, -3.0f,
        0.78539816f, 1.57079633f, 3.14159265f, 6.28318531f,
        10.0f, -10.0f, 100.0f, -100.0f, 1000.0f, -1000.0f,
        1.0e10f, -1.0e10f, FLT_MAX, -FLT_MAX,
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit(vals[i]);

    /* sweep [-4*pi, 4*pi] */
    float hi = 4.0f * 3.14159265f;
    for (int i = 0; i <= 200; i++)
        emit(-hi + (2.0f * hi) * (float)i / 200.0f);

    return 0;
}

